arguments.file_text:
@typeparam TItem

@if (_items.Count == 0)
{
    if (EmptyTemplate is not null)
    {
        @EmptyTemplate
    }
    else
    {
        <p>No items to display.</p>
    }
}
else
{
    <table>
        <thead>
            <tr>@HeaderTemplate</tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr @key="item" @onclick="() => OnRowClick.InvokeAsync(item)">
                    @RowTemplate!(item)
                </tr>
            }
        </tbody>
    </table>
}

